def clean_xml_text(text):
    """Clean up XML text content"""
    if not text:
        return ""
    # Remove extra whitespace and clean up
    text = text.strip()
    # Replace multiple spaces with single space
    text = re.sub(r'\s+', ' ', text)
    return text

